import re
import os

# Check message.py for unused imports
with open("src/modules/message.py") as f:
    content = f.read()

# Get all imports
import_pattern = r'^(?:from|import)\s+(.+?)(?:\s+as\s+\w+)?$'
imports = {}
for line_num, line in enumerate(content.split('\n')[:100], 1):
    match = re.match(import_pattern, line)
    if match:
        module = match.group(1).strip()
        # Extract the actual symbol
        if 'from' in line:
            parts = re.match(r'from\s+\S+\s+import\s+(.+)', line)
            if parts:
                symbols = [s.strip().split(' as ')[-1] for s in parts.group(1).split(',')]
                for sym in symbols:
                    imports[sym] = line_num
        else:
            imports[module] = line_num

# Check what's used
for sym in imports:
    if sym and sym.startswith('_'):
        continue  # Skip private imports
    pattern = rf'\b{re.escape(sym)}\b'
    usage_count = len(re.findall(pattern, content))
    # Rough check - more than 2 usually means it's imported and used
    if usage_count < 2:
        print(f"Possibly unused: {sym} (imported line {imports[sym]}, used {usage_count} times)")
EOF
